    override fun lower(value: BundleDescriptor): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): BundleDescriptor {
        return BundleDescriptor(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): BundleDescriptor {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: BundleDescriptor) = 8UL

    override fun write(value: BundleDescriptor, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
